steps.script:
var dlg=null
for n in tree.root.get_children():
	if n is ConfirmationDialog and n.visible:
		dlg=n
if dlg==null:
	return false
dlg.get_ok_button().emit_signal("pressed")
return true

var dlg=null
for n in tree.root.get_children():
	if str(n.name).to_lower().contains("reroll") and n.visible:
		dlg=n
if dlg==null:
	return "no_reroll"
var stack=[dlg]
while stack.size()>0:
	var nd=stack.pop_back()
	if nd is Button and str(nd.name)=="KeepRollButton":
		nd.emit_signal("pressed")
		return "declined"
	for c in nd.get_children():
		stack.append(c)
return "no_button"
